import ImageList from '@material-ui/core/ImageList';
import ImageListItem from '@material-ui/core/ImageListItem';
import ImageListItemBar from '@material-ui/core/ImageListItemBar';
import Dialog from '@material-ui/core/Dialog';
import DialogTitle from '@material-ui/core/DialogTitle';
import DialogContent from '@material-ui/core/DialogContent';
import IconButton from '@material-ui/core/IconButton';
import CloseButton from '@material-ui/icons/Close';
import Chip from '@material-ui/core/Chip';
import { makeStyles } from '@material-ui/core';

import { pink } from '@material-ui/core/colors';
import { useState } from 'react';

const useStyles = makeStyles((theme) => ({
	card: {
		display: 'flex',
		flexWrap: 'wrap',
		justifyContent: 'space-around',
		overflow: 'hidden',
		backgroundColor: '#291755',
	},
	dialog: {
		display: 'flex',
		flexWrap: 'wrap',
		justifyContent: 'space-around',
		overflow: 'hidden',
		color: pink[500],
		fontWeight: 'bold',
	},
	image: {
		cursor: 'pointer',
		'&:hover': {
			borderColor: pink[500],
			border: '5px solid',
			padding: 5,
		},
	},
	gameList: {
		justifyContent: 'center',
		height: '60%',
		width: '100%',
		backgroundColor: '#291755',
		overflow: 'hidden',
	},
	screenList: {
		flexWrap: 'nowrap',
		transform: 'translateZ(0)',
	},
	title: {
		color: 'white',
	},
	subheader: {
		marginBottom: 20,
		fontSize: 25,
	},
	closeButton: {
		position: 'absolute',
		right: theme.spacing(1),
		top: theme.spacing(1),
		color: theme.palette.grey[500],
	},
}));

const Item = ({ gameData, term }) => {
	const classes = useStyles();

	const name = gameData.map((item) => item.name);
	const dates = gameData.map((item) => item.released);

	const [gameName, setGameName] = useState(name);
	const [date, setDate] = useState(dates);
	const [genre, setGenre] = useState([]);
	const [screen, setScreen] = useState(null);
	const [open, setOpen] = useState(false);

	const handleClickOpen = (e) => {
		setOpen(true);

		// getting game title in dialog
		for (let i = 0; i < name.length; i++) {
			if (e.target.alt === name[i]) {
				setGameName(e.target.alt);
			}
		}

		// getting release date in dialog
		let value = e.target.alt;
		const index = gameData.findIndex((item) => item.name === value);
		setDate(dates[index]);

		// getting screenshots in dialog
		const images = gameData[index].short_screenshots.slice(1, 6);
		setScreen(images);

		// getting genres in dialog
		const eachGenres = [];

		for (let i = 0; i < gameData[index].genres.length; i++) {
			eachGenres.push(gameData[index].genres[i].name);
		}

		setGenre(eachGenres);
	};

	const handleClose = () => {
		setOpen(false);
	};

	return (
		<div className={classes.card}>
			{term ? null : (
				<h2 style={{ color: 'white', marginTop: 5 }}>Popular Games</h2>
			)}
			<ImageList className={classes.gameList} cols={3.2}>
				{gameData.map((item) => (
					<ImageListItem key={item.slug} className={classes.image}>
						<img
							src={item.background_image}
							alt={item.name}
							onClick={handleClickOpen}
						/>
						<ImageListItemBar
							title={
								<span style={{ fontSize: '1.5em', fontWeight: 'bold' }}>
									{item.name}
								</span>
							}
							subtitle={
								<div>
									<span style={{ marginRight: '2em' }}>
										Metacritic: <span>{item.metacritic}</span>
									</span>
								</div>
							}
							classes={{
								root: classes.titleBar,
								title: classes.title,
							}}
						/>
					</ImageListItem>
				))}
			</ImageList>

			{/* Dialog Content */}
			<Dialog onClose={handleClose} open={open}>
				<DialogTitle
					style={{
						paddingBottom: 3,
						fontWeight: 'bold',
					}}
				>
					{gameName}
					<IconButton
						className={classes.closeButton}
						onClick={handleClose}
						size="small"
					>
						<CloseButton />
					</IconButton>
				</DialogTitle>
				<DialogContent>
					<div className={classes.dialog}>
						<p>Screenshots</p>
						<ImageList className={classes.screenList} cols={1.7}>
							{screen
								? screen.map((item) => (
										<ImageListItem key={item.image}>
											<img src={item.image} alt="" />
										</ImageListItem>
								  ))
								: 'Not found '}{' '}
							;
						</ImageList>
						<div style={{ textAlign: 'center' }}>
							<p>Genres</p>
							{genre[0] ? <Chip label={genre[0]} /> : 'Not found'}
							{genre[1] && <Chip label={genre[1]} />}
							{genre[2] && <Chip label={genre[2]} />}
							{genre[3] && <Chip label={genre[3]} />}
						</div>
						{date ? (
							<div>
								<p>Release Date</p>
								<p style={{ color: 'white', fontWeight: 'normal' }}> {date}</p>
							</div>
						) : (
							'Not found'
						)}
					</div>
				</DialogContent>
				<DialogContent></DialogContent>
			</Dialog>
		</div>
	);
};

export default Item;
